class Solution:
    def maxAmount(self, initialCurrency, pairs1, rates1, pairs2, rates2):
        def best_multipliers(pairs, rates):
            currencies = {initialCurrency}
            edges = []
            for (a, b), r in zip(pairs, rates):
                currencies.add(a)
                currencies.add(b)
                edges.append((a, b, r))
                edges.append((b, a, 1.0 / r))
            mult = {c: 0.0 for c in currencies}
            mult[initialCurrency] = 1.0
            for _ in range(len(currencies)):
                changed = False
                for a, b, r in edges:
                    if mult[a] > 0 and mult[a] * r > mult[b]:
                        mult[b] = mult[a] * r
                        changed = True
                if not changed:
                    break
            return mult

        day1 = best_multipliers(pairs1, rates1)
        day2 = best_multipliers(pairs2, rates2)
        best = 1.0
        for c, amt in day1.items():
            if amt > 0 and day2.get(c, 0.0) > 0:
                back = amt / day2[c]
                if back > best:
                    best = back
        return best

