class Solution:
    def maxAmount(self, initialCurrency, pairs1, rates1, pairs2, rates2):
        def build_graph(pairs, rates):
            graph = {}
            for (a, b), r in zip(pairs, rates):
                graph.setdefault(a, []).append((b, r))
                graph.setdefault(b, []).append((a, 1.0 / r))
            return graph

        def multipliers(graph, start):
            mult = {start: 1.0}
            stack = [start]
            while stack:
                cur = stack.pop()
                for nxt, rate in graph.get(cur, []):
                    if nxt not in mult:
                        mult[nxt] = mult[cur] * rate
                        stack.append(nxt)
            return mult

        graph1 = build_graph(pairs1, rates1)
        graph2 = build_graph(pairs2, rates2)
        day1 = multipliers(graph1, initialCurrency)
        day2 = multipliers(graph2, initialCurrency)

        best = 1.0
        for currency, amt in day1.items():
            if currency in day2:
                back = amt / day2[currency]
                if back > best:
                    best = back
        return best

