var maxAmount = function(initialCurrency, pairs1, rates1, pairs2, rates2) {
    function buildGraph(pairs, rates) {
        const graph = new Map();
        for (let i = 0; i < pairs.length; i++) {
            const a = pairs[i][0], b = pairs[i][1];
            const r = rates[i];
            if (!graph.has(a)) graph.set(a, []);
            if (!graph.has(b)) graph.set(b, []);
            graph.get(a).push([b, r]);
            graph.get(b).push([a, 1.0 / r]);
        }
        return graph;
    }

    function multipliers(graph, start) {
        const mult = new Map();
        mult.set(start, 1.0);
        const stack = [start];
        while (stack.length) {
            const cur = stack.pop();
            const neighbors = graph.get(cur) || [];
            for (const [nxt, rate] of neighbors) {
                if (!mult.has(nxt)) {
                    mult.set(nxt, mult.get(cur) * rate);
                    stack.push(nxt);
                }
            }
        }
        return mult;
    }

    const graph1 = buildGraph(pairs1, rates1);
    const graph2 = buildGraph(pairs2, rates2);
    const day1 = multipliers(graph1, initialCurrency);
    const day2 = multipliers(graph2, initialCurrency);

    let best = 1.0;
    for (const [currency, amt] of day1) {
        if (day2.has(currency)) {
            const back = amt / day2.get(currency);
            if (back > best) best = back;
        }
    }
    return best;
};
